mapper.select:
SELECT ma.id AS attachmentId, ma.media_asset_id AS mediaAssetId, ma.owner_type AS ownerType, ma.owner_id AS ownerId, ma.attachment_role AS attachmentRole, ma.sort_order AS sortOrder, ma.is_cover AS isCover, ma.created_at AS createdAt, asset.storage_key AS storageKey, asset.original_file_name AS originalFileName, asset.content_type AS contentType, asset.file_size AS fileSize, asset.width, asset.height, asset.checksum FROM media_attachment ma INNER JOIN media_asset asset ON asset.id = ma.media_asset_id WHERE ma.owner_type = #{ownerType} AND ma.deleted_at IS NULL AND ma.owner_id IN
#{ownerId}
ORDER BY ma.owner_id ASC, ma.sort_order ASC, ma.id ASC

SELECT COUNT(*)
FROM media_attachment
WHERE owner_type = #{ownerType}
  AND owner_id = #{ownerId}
  AND deleted_at IS NULL

SELECT MAX(sort_order)
FROM media_attachment
WHERE owner_type = #{ownerType}
  AND owner_id = #{ownerId}
  AND deleted_at IS NULL
